files.content:
:root {
  --bg: #0a1410;
  --bg-elev: #11201b;
  --bg-card: rgba(17, 32, 27, 0.78);
  --border: rgba(66, 184, 131, 0.18);
  --border-strong: rgba(66, 184, 131, 0.42);
  --text: #e6f4ef;
  --muted: #87a698;
  --vue: #42b883;
  --vue-deep: #35495e;
  --accent: #41b8a7;
  --success: #4ade80;
  --warn: #fbbf24;
  --danger: #f87171;
  --code-bg: rgba(3, 10, 8, 0.85);
  --shadow: 0 30px 60px -20px rgba(0, 0, 0, 0.6);
  font-family: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI',
    Roboto, sans-serif;
}

* { box-sizing: border-box; }

html, body {
  margin: 0;
  padding: 0;
  min-height: 100%;
  background: var(--bg);
  color: var(--text);
  -webkit-font-smoothing: antialiased;
}

body {
  overflow-x: hidden;
  background:
    radial-gradient(900px 500px at 100% 0%, rgba(66, 184, 131, 0.22), transparent 60%),
    radial-gradient(800px 500px at 0% 100%, rgba(53, 73, 94, 0.4), transparent 60%),
    var(--bg);
}

.bg-grid {
  position: fixed;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  background-image:
    linear-gradient(rgba(66, 184, 131, 0.07) 1px, transparent 1px),
    linear-gradient(90deg, rgba(66, 184, 131, 0.07) 1px, transparent 1px);
  background-size: 48px 48px;
  mask-image: radial-gradient(ellipse at center, black 30%, transparent 80%);
  -webkit-mask-image: radial-gradient(ellipse at center, black 30%, transparent 80%);
  opacity: 0.55;
}

#app {
  position: relative;
  z-index: 1;
  max-width: 1080px;
  margin: 0 auto;
  padding: 56px 24px 80px;
}

.hero {
  text-align: center;
  margin-bottom: 56px;
}

.badge {
  display: inline-flex;
  align-items: center;
  gap: 10px;
  padding: 8px 14px;
  border: 1px solid var(--border);
  border-radius: 999px;
  background: rgba(17, 32, 27, 0.7);
  backdrop-filter: blur(8px);
  font-size: 12px;
  font-weight: 500;
  letter-spacing: 0.04em;
  text-transform: uppercase;
  color: var(--muted);
  margin-bottom: 24px;
}

h1 {
  font-size: clamp(2rem, 5vw, 3.4rem);
  line-height: 1.1;
  font-weight: 800;
  margin: 0 0 18px;
  letter-spacing: -0.02em;
}

.gradient-text {
  background: linear-gradient(120deg, var(--vue) 0%, var(--accent) 100%);
  -webkit-background-clip: text;
  background-clip: text;
  -webkit-text-fill-color: transparent;
}

.lede {
  max-width: 640px;
  margin: 0 auto 28px;
  color: var(--muted);
  font-size: 17px;
  line-height: 1.6;
}

.lede code, .card p code, .card h2 code {
  background: var(--code-bg);
  padding: 2px 6px;
  border-radius: 4px;
  color: var(--vue);
  font-size: 13px;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
}

.hero-actions {
  display: flex;
  gap: 12px;
  justify-content: center;
  flex-wrap: wrap;
}

.btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 12px 20px;
  border-radius: 10px;
  border: 1px solid transparent;
  font: inherit;
  font-size: 14px;
  font-weight: 600;
  cursor: pointer;
  transition: transform 0.15s ease, box-shadow 0.15s ease;
  color: var(--text);
  background: rgba(255, 255, 255, 0.05);
  white-space: nowrap;
  text-decoration: none;
}

.btn:hover { transform: translateY(-1px); }
.btn:disabled { opacity: 0.5; cursor: not-allowed; transform: none; }

.btn-primary {
  background: linear-gradient(120deg, var(--vue-deep), var(--vue));
  color: #fff;
  box-shadow: 0 12px 30px -10px rgba(66, 184, 131, 0.6);
}

.btn-ghost { background: transparent; border-color: var(--border-strong); }
.btn-small { padding: 8px 14px; font-size: 13px; }

.icon { font-size: 12px; }

.section-title {
  font-size: 13px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  color: var(--muted);
  margin: 40px 0 16px;
  display: flex;
  align-items: center;
  gap: 12px;
}

.section-title::before,
.section-title::after {
  content: '';
  flex: 1;
  height: 1px;
  background: var(--border);
}

.grid {
  display: grid;
  grid-template-columns: repeat(auto-fill, minmax(320px, 1fr));
  gap: 20px;
}

.card {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: 16px;
  padding: 22px;
  backdrop-filter: blur(12px);
  box-shadow: var(--shadow);
  display: flex;
  flex-direction: column;
  gap: 14px;
  transition: transform 0.2s ease, border-color 0.2s ease;
}

.card:hover {
  transform: translateY(-2px);
  border-color: var(--border-strong);
}

.card header { display: flex; flex-direction: column; gap: 8px; }

.tag {
  align-self: flex-start;
  font-size: 11px;
  font-weight: 600;
  letter-spacing: 0.06em;
  text-transform: uppercase;
  padding: 4px 10px;
  border-radius: 999px;
  background: rgba(66, 184, 131, 0.15);
  color: var(--vue);
}

.card h2 { font-size: 17px; margin: 0; font-weight: 700; }
.card p {
  margin: 0;
  color: var(--muted);
  font-size: 14px;
  line-height: 1.55;
}

/* Counter widget */
.counter {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
}

.counter-value {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 34px;
  font-weight: 700;
  color: var(--vue);
  min-width: 80px;
  text-align: center;
  font-variant-numeric: tabular-nums;
}

.counter-controls {
  display: flex;
  gap: 6px;
}

.counter-controls .btn-small {
  width: 36px;
  padding: 8px 0;
  justify-content: center;
}

/* Reactivity / computed */
.computed {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.computed-input {
  background: rgba(3, 10, 8, 0.6);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 10px 12px;
  color: var(--text);
  font: inherit;
  font-size: 14px;
  outline: none;
  transition: border-color 0.15s ease;
  width: 100%;
}

.computed-input:focus { border-color: var(--vue); }

.computed-stats {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 8px;
}

.stat {
  background: rgba(3, 10, 8, 0.5);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 8px 10px;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
}

.stat-label {
  font-size: 10px;
  font-weight: 600;
  letter-spacing: 0.08em;
  text-transform: uppercase;
  color: var(--muted);
}

.stat-value {
  font-size: 16px;
  font-weight: 700;
  color: var(--vue);
  font-variant-numeric: tabular-nums;
}

.stat-full {
  grid-column: 1 / -1;
}

.stat-full .stat-value {
  font-size: 14px;
  word-break: break-all;
}

.lang-icon {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 14px;
  font-weight: 700;
  color: var(--vue);
  min-width: 28px;
  text-align: center;
}

.lang-year {
  margin-left: auto;
  font-size: 12px;
  color: var(--muted);
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-variant-numeric: tabular-nums;
}

.lang-list {
  max-height: 180px;
}

/* Todos */
.todo-form { display: flex; gap: 8px; }
.todo-list {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  flex-direction: column;
  gap: 4px;
  max-height: 160px;
  overflow-y: auto;
}

.todo-item {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 6px 8px;
  border-radius: 6px;
  font-size: 14px;
}

.todo-item:hover { background: rgba(255, 255, 255, 0.03); }
.todo-item input[type="checkbox"] {
  accent-color: var(--vue);
  cursor: pointer;
  width: 16px;
  height: 16px;
  margin: 0;
}
.todo-item.done span { text-decoration: line-through; color: var(--muted); }
.todo-item .remove {
  margin-left: auto;
  background: none;
  border: none;
  color: var(--muted);
  cursor: pointer;
  font-size: 16px;
  line-height: 1;
  padding: 0 4px;
}
.todo-item .remove:hover { color: var(--danger); }
.todo-empty {
  font-size: 13px;
  color: var(--muted);
  text-align: center;
  padding: 16px 0;
  font-style: italic;
}

/* Watcher */
.watcher {
  display: flex;
  flex-direction: column;
  gap: 10px;
}

.watcher .feed {
  background: var(--code-bg);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 10px 12px;
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  font-size: 12px;
  line-height: 1.5;
  height: 110px;
  overflow-y: auto;
}

.watcher .feed-line { color: var(--muted); }
.watcher .feed-line .ts { color: var(--vue); margin-right: 8px; }
.watcher .empty { color: var(--muted); font-style: italic; }

/* Theme */
.theme-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 6px;
}

.swatch {
  height: 36px;
  border-radius: 8px;
  border: 2px solid transparent;
  cursor: pointer;
  transition: transform 0.15s ease, border-color 0.15s ease;
}

.swatch:hover { transform: scale(1.05); }
.swatch.active { border-color: var(--text); transform: scale(1.05); }

.theme-preview {
  padding: 14px;
  border-radius: 10px;
  text-align: center;
  font-weight: 700;
  border: 1px solid var(--border);
  transition: background 0.3s ease, color 0.3s ease;
}

/* List rendering */
.tabs {
  display: flex;
  gap: 4px;
  background: rgba(3, 10, 8, 0.5);
  border: 1px solid var(--border);
  border-radius: 8px;
  padding: 4px;
}

.tab {
  flex: 1;
  background: transparent;
  border: none;
  border-radius: 6px;
  padding: 6px 8px;
  color: var(--muted);
  font: inherit;
  font-size: 12px;
  font-weight: 600;
  cursor: pointer;
  transition: background 0.15s ease, color 0.15s ease;
}

.tab.active { background: var(--vue); color: #0a1410; }

.foot {
  text-align: center;
  margin-top: 56px;
  color: var(--muted);
  font-size: 13px;
}

.kbd {
  font-family: 'JetBrains Mono', ui-monospace, monospace;
  background: rgba(255, 255, 255, 0.06);
  padding: 2px 6px;
  border-radius: 4px;
  border: 1px solid var(--border);
  font-size: 11.5px;
}

@media (max-width: 640px) {
  #app { padding: 32px 16px 56px; }
  .card { padding: 18px; }
}

import { createApp } from 'vue';
import App from './App.vue';

createApp(App).mount('#app');

const path = require('path');
const { VueLoaderPlugin } = require('vue-loader');

const config = {
  mode: 'development',
  entry: './src/index.js',
  output: {
    path: path.resolve(__dirname, 'dist'),
    filename: 'bundle.js'
  },
  module: {
    rules: [
      {
        test: /\.vue$/,
        loader: 'vue-loader'
      },
      {
        test: /\.css$/,
        use: [
          'style-loader',
          'css-loader'
        ]
      },
      {
        test: /\.(png|jpg|gif|svg)$/,
        loader: 'file-loader',
        options: {
            name: '[name].[ext]?[hash]',
            esModule: false
        }
      }
    ]
  },
  resolve: {
    extensions: [
      '.js',
      '.vue'
    ],
    modules:[
      'node_modules',
      path.join(process.env.NPM_CONFIG_PREFIX || __dirname, 'lib/node_modules')
    ]
  },
  resolveLoader: {
    modules:[
      'node_modules',
      path.join(process.env.NPM_CONFIG_PREFIX || __dirname, 'lib/node_modules')
    ]
  },
  plugins: [
    new VueLoaderPlugin()
  ]
};

module.exports = config;
